action.command:
cd /workspace/oxc && printf -- '--- README commands ---\n' && sed -n '1,180p' README.md | sed -n '/## Quick Start/,$p' && printf -- '\n--- Cargo packages matching language/lsp ---\n' && cargo metadata --no-deps --format-version 1 2>/dev/null | python3 - <<'PY'
import sys,json
try:
    data=json.load(sys.stdin)
except Exception as e:
    print(e); sys.exit(0)
for p in data['packages']:
    if 'language' in p['name'] or 'lsp' in p['name'] or 'server' in p['name']:
        print(p['name'], p['manifest_path'])
PY
printf -- '\n--- find language server dirs ---\n' && find crates -maxdepth 3 -iname '*language*' -o -iname '*lsp*' | sort | head -50

