   316	    /// Common implementation for handling tool changes that may result in
   317	    /// diagnostics updates, watcher registrations/unregistrations, and tool replacement
   318	    async fn handle_tool_changes<F>(
   319	        &self,
   320	        file_system: Option<&LSPFileSystem>,
   321	        needs_diagnostic_refresh: &mut bool,
   322	        change_handler: F,
   323	    ) -> (Option<Vec<(Uri, Vec<Diagnostic>)>>, Vec<Registration>, Vec<Unregistration>)
   324	    where
   325	        F: Fn(&mut Box<dyn Tool>, &dyn ToolBuilder) -> ToolRestartChanges,
   326	    {
   327	        let mut registrations = vec![];
   328	        let mut unregistrations = vec![];
   329	        let mut diagnostics: Option<Vec<(Uri, Vec<Diagnostic>)>> = None;
   330	
   331	        let mut tools = self.tool.write().await;
   332	        let Some(tool) = tools.as_mut() else {
   333	            // No tool to update, return early
   334	            return (None, registrations, unregistrations);
   335	        };
   336	        let change = change_handler(tool, self.builder.as_ref());
   337	
   338	        if let Some(patterns) = change.watch_patterns {
   339	            unregistrations.push(unregistration_tool_watcher_id(tool.name(), &self.root_uri));
   340	            if !patterns.is_empty() {
   341	                registrations.push(registration_tool_watcher_id(
   342	                    tool.name(),
   343	                    &self.root_uri,
   344	                    patterns,
   345	                ));
   346	            }
   347	        }
   348	        if let Some(replaced_tool) = change.tool {
   349	            *tool = replaced_tool;
   350	            *needs_diagnostic_refresh = true;
   351	
   352	            let Some(file_system) = file_system else {
   353	                return (None, registrations, unregistrations);
   354	            };
   355	
   356	            for uri in file_system.keys() {
   357	                let document = file_system.get_document(&uri);
   358	                let Ok(mut reports) = tool.run_diagnostic(&document) else {
   359	                    // If diagnostics could not be run, skip this URI, but continue with others
   360	                    // TODO: Should we aggregate errors instead? One by one, or all together?
   361	                    continue;
   362	                };
   363	                if !reports.is_empty() {
   364	                    if let Some(existing_diagnostics) = &mut diagnostics {
   365	                        existing_diagnostics.append(&mut reports);
   366	                    } else {
   367	                        diagnostics = Some(reports);
   368	                    }
   369	                }
   370	            }
   371	        }
   372	
   373	        (diagnostics, registrations, unregistrations)
   374	    }
