fn build_unused_disable_diagnostic_report(
    message: String,
    span: Span,
    severity: DiagnosticSeverity,
    source_text: &str,
    rope: &Rope,
    fix: Option<&Fix>,
) -> DiagnosticReport {
    let start_position = offset_to_position(rope, span.start, source_text);
    let end_position = offset_to_position(rope, span.end, source_text);
    let range = Range::new(start_position, end_position);

    DiagnosticReport {
        diagnostic: Diagnostic {
            range,
            severity: Some(severity),
            code: Some("".into()),
            message,
            source: Some("oxc".into()),
            code_description: None,
            related_information: None,
            tags: None,
            data: None,
        },
        code_action: fix.map(|fix| {
            let mut fix = fix.clone();
            if fix.span == span
                && let Some(line_span) = standalone_comment_line_span(source_text, fix.span)
            {
                fix.span = line_span;
            }

            LinterCodeAction {
                range,
                fixed_content: vec![fix_to_fixed_content(
                    &fix,
                    rope,
                    source_text,
                    FixedContentKind::UnusedDirective,
                )],
            }
        }),
    }
}

fn standalone_comment_line_span(source_text: &str, content_span: Span) -> Option<Span> {
    let start = usize::try_from(content_span.start).ok()?;
    let end = usize::try_from(content_span.end).ok()?;
    if start > end || end > source_text.len() {
        return None;
    }

    let line_start = source_text.get(..start)?.rfind('\n').map_or(0, |index| index + 1);
    let newline_start = source_text.get(end..)?.find('\n').map(|index| end + index);
    let line_end = newline_start.unwrap_or(source_text.len());
    let line_end_including_newline = newline_start.map_or(line_end, |index| index + 1);
    let line_end_without_newline = if line_end > line_start
        && source_text.as_bytes().get(line_end - 1) == Some(&b'\r')
    {
        line_end - 1
    } else {
        line_end
    };

    let (comment_start, comment_end) = if start >= 2
        && source_text.get(start - 2..start) == Some("//")
    {
        (start - 2, line_end_without_newline)
    } else if start >= 2
        && source_text.get(start - 2..start) == Some("/*")
        && source_text.get(end..end.checked_add(2)?) == Some("*/")
    {
        (start - 2, end + 2)
    } else {
        return None;
    };

    if source_text.get(line_start..comment_start)?.trim().is_empty()
        && source_text.get(comment_end..line_end_without_newline)?.trim().is_empty()
    {
        let start = u32::try_from(line_start).ok()?;
        let end = u32::try_from(line_end_including_newline).ok()?;
        Some(Span::new(start, end))
    } else {
        None
    }
}

