#!/usr/bin/env python3
import json, os, subprocess, sys, time, select, tempfile
from pathlib import Path

REPO = Path('/workspace/oxc')
BIN = REPO / 'target/debug/oxlint'


def send(proc, msg):
    data = json.dumps(msg, separators=(',', ':')).encode()
    proc.stdin.write(b'Content-Length: ' + str(len(data)).encode() + b'\r\n\r\n' + data)
    proc.stdin.flush()


def read_msg(proc, timeout=10):
    fd = proc.stdout.fileno()
    start = time.time()
    header = b''
    while b'\r\n\r\n' not in header:
        if time.time() - start > timeout:
            raise TimeoutError('timeout waiting for LSP header')
        r, _, _ = select.select([fd], [], [], 0.1)
        if not r:
            continue
        chunk = os.read(fd, 1)
        if not chunk:
            raise EOFError('LSP server closed stdout')
        header += chunk
    headers, rest = header.split(b'\r\n\r\n', 1)
    length = None
    for line in headers.decode().split('\r\n'):
        if line.lower().startswith('content-length:'):
            length = int(line.split(':', 1)[1].strip())
    if length is None:
        raise RuntimeError(f'missing content-length in {headers!r}')
    body = rest
    while len(body) < length:
        if time.time() - start > timeout:
            raise TimeoutError('timeout waiting for LSP body')
        r, _, _ = select.select([fd], [], [], 0.1)
        if r:
            body += os.read(fd, length - len(body))
    return json.loads(body[:length])


def request(proc, next_id, method, params):
    send(proc, {'jsonrpc': '2.0', 'id': next_id, 'method': method, 'params': params})
    while True:
        msg = read_msg(proc)
        if 'method' in msg and 'id' in msg:
            result = [{'unusedDisableDirectives': 'deny'}] if msg['method'] == 'workspace/configuration' else None
            send(proc, {'jsonrpc': '2.0', 'id': msg['id'], 'result': result})
            continue
        if msg.get('id') == next_id:
            return msg.get('result')


def apply_edits(text, edits):
    lines = text.splitlines(keepends=True)
    def offset(pos):
        return sum(len(line) for line in lines[:pos['line']]) + pos['character']
    spans = [(offset(e['range']['start']), offset(e['range']['end']), e.get('newText', '')) for e in edits]
    for start, end, new in sorted(spans, reverse=True):
        text = text[:start] + new + text[end:]
    return text


def run_fix_all(root: Path, rel_file: str, text: str):
    file = root / rel_file
    uri = file.as_uri()
    root_uri = root.as_uri()
    proc = subprocess.Popen([str(BIN), '--lsp'], cwd=root, stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    try:
        initialize = request(proc, 1, 'initialize', {
            'processId': os.getpid(),
            'rootUri': root_uri,
            'workspaceFolders': [{'uri': root_uri, 'name': root.name}],
            'capabilities': {'textDocument': {'codeAction': {'codeActionLiteralSupport': {'codeActionKind': {'valueSet': ['quickfix', 'source.fixAll', 'source.fixAll.oxc']}}}}},
            'initializationOptions': {'settings': {'unusedDisableDirectives': 'deny'}},
        })
        assert initialize and 'capabilities' in initialize
        send(proc, {'jsonrpc': '2.0', 'method': 'initialized', 'params': {}})
        send(proc, {'jsonrpc': '2.0', 'method': 'textDocument/didOpen', 'params': {'textDocument': {'uri': uri, 'languageId': 'javascript', 'version': 1, 'text': text}}})
        diagnostics = []
        deadline = time.time() + 10
        while time.time() < deadline:
            msg = read_msg(proc, timeout=max(0.1, deadline - time.time()))
            if 'method' in msg and 'id' in msg:
                result = [{'unusedDisableDirectives': 'deny'}] if msg['method'] == 'workspace/configuration' else None
                send(proc, {'jsonrpc': '2.0', 'id': msg['id'], 'result': result})
            elif msg.get('method') == 'textDocument/publishDiagnostics' and msg.get('params', {}).get('uri') == uri:
                diagnostics = msg['params'].get('diagnostics', [])
                if diagnostics:
                    break
        actions = request(proc, 2, 'textDocument/codeAction', {
            'textDocument': {'uri': uri},
            'range': {'start': {'line': 0, 'character': 0}, 'end': {'line': 999, 'character': 999}},
            'context': {'diagnostics': diagnostics, 'only': ['source.fixAll.oxc'], 'triggerKind': 1},
        })
        edits = actions[0]['edit']['changes'][uri]
        return apply_edits(text, edits), edits
    finally:
