+fn standalone_comment_line_span(source_text: &str, content_span: Span) -> Option<Span> {
+    let start = usize::try_from(content_span.start).ok()?;
+    let end = usize::try_from(content_span.end).ok()?;
+    if start > end || end > source_text.len() {
+        return None;
+    }
+
+    let line_start = source_text.get(..start)?.rfind('\n').map_or(0, |index| index + 1);
+    let newline_start = source_text.get(end..)?.find('\n').map(|index| end + index);
+    let line_end = newline_start.unwrap_or(source_text.len());
+    let line_end_including_newline = newline_start.map_or(line_end, |index| index + 1);
+    let line_end_without_newline =
+        if line_end > line_start && source_text.as_bytes().get(line_end - 1) == Some(&b'\r') {
+            line_end - 1
+        } else {
+            line_end
+        };
+
+    let block_end = end.checked_add(2)?;
+    let (comment_start, comment_end) =
+        if start >= 2 && source_text.get(start - 2..start) == Some("//") {
+            (start - 2, line_end_without_newline)
+        } else if start >= 2
+            && source_text.get(start - 2..start) == Some("/*")
